                    }
                    false => ssh_capture(ip, ssh_user, &ssh_priv_path, cmd),
                },
                |cmd| match cp_needs_jump {
                    true => ssh_run_jump(&jumphost_ip, ssh_user, ip, ssh_user, &ssh_priv_path, cmd),
                    false => ssh_run(ip, ssh_user, &ssh_priv_path, cmd),
